/* This function attempts to keep backwards compatibility with value and defaultValue props type */

/**
 * @typedef {Object} ComputeValueTypeProps
 * @prop {string | number | string[]} [defaultValueProp]
 * @prop {string | number | string[]} [valueProp]
 */

/** @param {ComputeValueTypeProps} props */
const computeValueType = ({ defaultValueProp, valueProp }) => {
  const computeDefaultValue = typeof defaultValueProp === 'number' ? String(defaultValueProp) : defaultValueProp;
  const computeValue = typeof valueProp === 'number' ? String(valueProp) : valueProp;

  return { value: computeValue, defaultValue: computeDefaultValue };
};

export default computeValueType;
