/**
 * @typedef {Object} TriggerDisplayValuesProps
 * @prop {string | string[]} [values]
 * @prop {boolean} [multiple]
 * @prop {Record<string, { isSlotted: Boolean; content: string }>} itemsPrimaryReference
 */

/**
 * @param {TriggerDisplayValuesProps} props
 * @returns {string | string[] | undefined}
 */
const getTriggerDisplayValues = ({ values, multiple, itemsPrimaryReference }) => {
  let displayValues;

  if (typeof values === 'undefined') return displayValues;

  if (Array.isArray(values)) {
    displayValues = values.map((selectedValue) => {
      const { isSlotted, content } = itemsPrimaryReference[selectedValue] || {};
      return isSlotted ? selectedValue : content;
    });
  } else {
    const { isSlotted, content } = itemsPrimaryReference[values] || {};
    displayValues = isSlotted ? values : content;
  }

  if (displayValues && multiple && !Array.isArray(displayValues)) {
    displayValues = [displayValues];
  }

  return displayValues;
};

export default getTriggerDisplayValues;
