import { DROPDOWN_ARROW_SPACING, MAX_TAG_LIMIT, TAG_SMALL_LETTER_WIDTH, TAG_SMALL_OFFSET } from '../constants/layout';

/**
 * @param {string | string[]} currentDisplayValues
 * @param {import('react').MutableRefObject<HTMLDivElement | null>} containerRef
 */
export const calculateTagLimit = (currentDisplayValues, containerRef) => {
  const containerWidth = /** @type {HTMLDivElement} */ (containerRef?.current)?.offsetWidth;
  let totalLength = 0;
  let calculatedTagLimit = MAX_TAG_LIMIT;

  // eslint-disable-next-line no-restricted-syntax
  for (const [labelIndex, currentLabel] of Object.entries(currentDisplayValues)) {
    const currentLabelLength = currentLabel?.toString().length * TAG_SMALL_LETTER_WIDTH + TAG_SMALL_OFFSET;

    if ((totalLength + currentLabelLength + DROPDOWN_ARROW_SPACING > containerWidth)) {
      calculatedTagLimit = parseInt(labelIndex, 10);
      break;
    }

    totalLength += currentLabelLength;
  }

  return calculatedTagLimit;
};

