import React from 'react';
import PropTypes from 'prop-types';
import { DROPDOWN_NATIVE_ITEM_DISPLAY_NAME } from '../constants/components';

/** @type {typeof import('../..').DropdownNativeItem} */
const DropdownNativeItem = ({
  selected = false,
  disabled = false,
  value,
  title,
  children,
}) => (
  <option
    selected={selected || undefined}
    disabled={disabled}
    value={value}
  >
    {title || children}
  </option>
);

DropdownNativeItem.displayName = DROPDOWN_NATIVE_ITEM_DISPLAY_NAME;

DropdownNativeItem.propTypes = {
  children: PropTypes.node,
  disabled: PropTypes.bool,
  selected: PropTypes.bool,
  title: PropTypes.string,
  value: PropTypes.string.isRequired,
};

export default DropdownNativeItem;
