import React, { useCallback } from 'react';
import PropTypes from 'prop-types';
import { Tag, TagCollapsed } from '@andes/tag';
import { calculateTagLimit } from '../utils/calculateTagLimit';

/**
 * @typedef {Object} TagContentProps
 * @prop {string | string[]} [currentDisplayValues]
 * @prop {string[]} [currentValues]
 * @prop {boolean} [disabled]
 * @prop {string} [namespace]
 * @prop {React.RefObject<HTMLDivElement | null>} containerRef
 * @prop {string} id
 * @prop {(
 *  event: React.KeyboardEvent | React.MouseEvent,
 *  value?: string | string[]
 * ) => void} onSelectionChange
 * @prop {import('../..').DropdownFormProps['renderMultipleTriggerContent']} [renderMultipleTriggerContent]
 */

/** @type {React.FunctionComponent<TagContentProps>} */
const TagContent = ({
  currentDisplayValues = [],
  currentValues = [],
  disabled = false,
  namespace = '',
  containerRef,
  id,
  onSelectionChange,
  renderMultipleTriggerContent,
}) => {
  const currentDisplayValuesHasItems = Array.isArray(currentDisplayValues) && currentDisplayValues.length > 0;

  const handleClose = useCallback(/** @param {number} index */ (index) =>
    /** @param {React.MouseEvent<HTMLButtonElement>} event */ (event) => {
      if (disabled) return;

      const newValues = currentValues.filter((_, i) => i !== index);
      onSelectionChange(event, newValues);
    }, [currentValues, disabled, onSelectionChange]);

  /** @param {React.MouseEvent<HTMLDivElement>} event */
  const handleClick = (event) => {
    event.stopPropagation();
  };

  const getTagCollapsedProps = useCallback(
    /** @param {string | string[]} displayValues */ (displayValues) => ({
      id: `${id}-display-values`,
      disabled,
      limit: calculateTagLimit(displayValues, containerRef),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }), [disabled, id]);

  const getTagProps = useCallback(
    /**
     * @param {string} displayValue
     * @param {number} index
     */
    (displayValue, index) => ({
      id: `${id}-tag-${index}`,
      size: /** @type {'small' | 'large'} */ ('small'),
      disabled,
      label: displayValue,
      onClose: handleClose(index),
    }), [disabled, id, handleClose]);

  if (typeof renderMultipleTriggerContent === 'function') {
    return (
      <div className={`${namespace}__display-container`} id={`${id}-display-values`}>
        {renderMultipleTriggerContent(currentValues, { getTagCollapsedProps, getTagProps })}
      </div>
    );
  }

  if (!currentDisplayValuesHasItems) return null;

  return (
    // eslint-disable-next-line jsx-a11y/no-static-element-interactions, jsx-a11y/click-events-have-key-events
    <div
      className={`${namespace}__display-container`}
      id={`${id}-display-values`}
      onClick={handleClick}
    >
      <TagCollapsed {...getTagCollapsedProps(currentDisplayValues)}>
        {currentDisplayValues.map((displayValue, index) => (
          <Tag key={`${displayValue}_${index}`} {...getTagProps(displayValue, index)} />
        ))}
      </TagCollapsed>
    </div>
  );
};

TagContent.propTypes = {
  currentDisplayValues: PropTypes.oneOfType([PropTypes.string.isRequired, PropTypes.arrayOf(PropTypes.string.isRequired)]),
  currentValues: PropTypes.arrayOf(PropTypes.string.isRequired),
  disabled: PropTypes.bool,
  namespace: PropTypes.string,
  // current could be HTMLDivElement or null, we can't use HTMLDivElement on prop types because it's undefined on SSR
  containerRef: PropTypes.shape({
    current: PropTypes.oneOfType([PropTypes.node, PropTypes.object]),
  }).isRequired,
  id: PropTypes.string.isRequired,
  onSelectionChange: PropTypes.func.isRequired,
  renderMultipleTriggerContent: PropTypes.func,
};

export default TagContent;
